import styles from './DashboardLevel3.module.css'
import { FiArrowLeft } from 'react-icons/fi'
import { useNavigate, useLocation } from 'react-router-dom'
import { lazy, useContext, useState } from 'react'
import AppContext from '../../context'
import { formatDate } from 'date-fns'
import { TbRefreshDot } from 'react-icons/tb'
import { IoIosArrowBack, IoIosArrowForward } from 'react-icons/io'

// Export Page
const DashboardLevel3SensorPage = lazy(() => import('./DashboardLevel3Sensor'))
const DashboardLevel3FollErrPage = lazy(() => import('./DashboardLevel3FollErr'))
const DashboardLevel3CenterlinePage = lazy(() => import('./DashboardLevel3Centerline'))

export default function DashboardV3() {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextVersion = context.version
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    const navigate = useNavigate()
    const location = useLocation()
    // ========================================= GLOBAL CONTEXT =========================================  //

    const allDashboardItems = [
        { id: 'sensor', title: 'Sensor' },
        { id: 'following_error', title: 'Following Error' },
        { id: 'centerline', title: 'Centerline' },
    ]
    const [startIndex, setStartIndex] = useState(0)
    const displayedItems = allDashboardItems.slice(startIndex, startIndex + 1)
    const currentTitle = displayedItems.length > 0 ? displayedItems[0].title : 'Tidak ada item'

    // ========================================= STATE VIEW =========================================  //
    const { link_up } = location.state || {}

    const cache = (() => {
        const cache = localStorage.getItem("cache")
        if (cache == null) {
            return { start_date: new Date(), end_date: new Date(), isRealtime: true }
        } else {
            const data = JSON.parse(cache)
            return {
                start_date: data.start_date,
                end_date: data.end_date,
                isRealtime: data.isRealtime,
            }
        }
    })()

    interface FilterType { start_date: Date; end_date: Date; }
    const [filterDate, setFilterDate] = useState<FilterType>({
        start_date: cache.start_date,
        end_date: cache.end_date
    })

    const [isRealtime, setIsRealtime] = useState<boolean>(cache.isRealtime ?? true)
    const [clickRefresh, setClickRefresh] = useState(0)
    // ========================================= STATE VIEW =========================================  //


    // ========================================= FUNCTIONS =========================================  //
    const handleToggle = () => {
        setIsRealtime((prev) => !prev)
    }

    const handleClickRefresh = () => {
        setClickRefresh((prev) => prev + 1)
    }

    const handleFilterDateChange = (newFilter: FilterType) => {
        setFilterDate(newFilter)
    }

    const handleNext = () => {
        if (startIndex + 1 < allDashboardItems.length) {
            setStartIndex(prevIndex => prevIndex + 1)
        }
    }

    const handlePrev = () => {
        if (startIndex > 0) {
            setStartIndex(prevIndex => prevIndex - 1)
        }
    }
    // ========================================= FUNCTIONS =========================================  //


    return (
        <div className='container'>
            {/* Header */}
            <div className={styles.cardHeader}>
                <div className={styles.leftMidWrapper}>
                    <div className={styles.leftSection}>
                        <button className={styles.backButton} onClick={() => navigate(-1)}>
                            <FiArrowLeft size={40} style={{ color: "var(--secondary-color)" }} />
                        </button>
                    </div>
                    <div className={styles.leftSection2}>
                        {link_up.link_up}
                    </div>

                    <div className={styles.midSection}>
                        <button className={styles.buttonFooter} disabled={isRealtime} onClick={handleClickRefresh}>
                            <TbRefreshDot />
                        </button>

                        <div className={styles.inputGroup}>
                            <label htmlFor="startDate">START DATE :</label>
                            <input
                                type="date"
                                value={formatDate(filterDate.start_date, "yyyy-MM-dd")}
                                onChange={(e) =>
                                    setFilterDate((prev) => ({
                                        ...prev,
                                        start_date: new Date(e.target.value),
                                    }))
                                }
                                className={styles.dateInput}
                                disabled={isRealtime}
                                style={{
                                    border: "0px solid black",
                                    borderRadius: "5px",
                                    backgroundColor: isRealtime ? "#eee" : "white",
                                    color: "var(--header-color-hover)",
                                }}
                            />
                        </div>

                        <div className={styles.inputGroup}>
                            <label htmlFor="endDate">END DATE :</label>
                            <input
                                type="date"
                                value={formatDate(filterDate.end_date, "yyyy-MM-dd")}
                                onChange={(e) =>
                                    setFilterDate((prev) => ({
                                        ...prev,
                                        end_date: new Date(e.target.value),
                                    }))
                                }
                                className={styles.dateInput}
                                disabled={isRealtime}
                                style={{
                                    border: "0px solid black",
                                    borderRadius: "5px",
                                    backgroundColor: isRealtime ? "#eee" : "white",
                                    color: "var(--header-color-hover)",
                                }}
                            />
                        </div>

                        <div className={styles.switchGroup}>
                            <label htmlFor="realtime">Realtime</label>
                            <label className={styles.switch}>
                                <input
                                    type="checkbox"
                                    id="realtime"
                                    checked={isRealtime}
                                    onChange={handleToggle}
                                />
                                <span className={styles.slider}></span>
                            </label>
                        </div>
                    </div>

                </div>

                <div className={styles.rightSection}>
                    <button onClick={handlePrev} disabled={startIndex === 0}>
                        <IoIosArrowBack />
                    </button>
                    <div>{currentTitle}</div>
                    <button onClick={handleNext} disabled={startIndex + 1 >= allDashboardItems.length}>
                        <IoIosArrowForward />
                    </button>
                </div>
            </div>

            {/* Body */}
            <div className={styles.cardContainer} >
                {displayedItems.map(item => (
                    <>
                        {item.id === 'sensor' && (
                            <DashboardLevel3SensorPage
                                realtime={isRealtime}
                                refresh={clickRefresh}
                                filterDate={filterDate}
                                onFilterDateChange={handleFilterDateChange}
                            />
                        )}

                        {item.id === 'following_error' && (
                            <DashboardLevel3FollErrPage
                                realtime={isRealtime}
                                refresh={clickRefresh}
                                filterDate={filterDate}
                                onFilterDateChange={handleFilterDateChange}
                            />
                        )}

                        {item.id === 'centerline' && (
                            <DashboardLevel3CenterlinePage
                                realtime={isRealtime}
                                refresh={clickRefresh}
                                filterDate={filterDate}
                                onFilterDateChange={handleFilterDateChange}
                            />
                        )}
                    </>
                ))}
            </div>
        </div >
    )
}